            columns = "*";
        }
        
        query.Append("SELECT ");
        
        if (!string.IsNullOrEmpty(limit) && int.TryParse(limit, out int limitValue))
        {
            query.Append($"TOP {limitValue} ");
        }
        
        query.Append($"{columns} FROM {tableName}");
        
        List<string> whereConditions = new List<string>();
        
        foreach (var param in queryParams)
        {
            string key = param.Key;
            
            if (key == "table" || key == "columns" || key == "orderBy" || key == "limit")
            {
