            }
            
            string value = param.Value.ToString();
            
            if (string.IsNullOrEmpty(value))
            {
                continue;
            }
            
            if (key.EndsWith("_min"))
            {
                string columnName = key.Substring(0, key.Length - 4);
                whereConditions.Add($"{columnName} >= {value}");
            }
            else if (key.EndsWith("_max"))
            {
                string columnName = key.Substring(0, key.Length - 4);
                whereConditions.Add($"{columnName} <= {value}");
            }
            else if (key.EndsWith("_like"))
            {
                string columnName = key.Substring(0, key.Length - 5);
                whereConditions.Add($"{columnName} LIKE '%{value}%'");
            }
            else if (key.EndsWith("_in"))
            {
                string columnName = key.Substring(0, key.Length - 3);
                string[] values = value.Split(',');
                string inClause = string.Join(",", Array.ConvertAll(values, v => $"'{v.Trim()}'"));
                whereConditions.Add($"{columnName} IN ({inClause})");
            }
            else if (key.EndsWith("_not"))
            {
                string columnName = key.Substring(0, key.Length - 4);
                whereConditions.Add($"{columnName} != '{value}'");
            }
            else if (key.EndsWith("_null"))
            {
                string columnName = key.Substring(0, key.Length - 5);
                if (value.ToLower() == "true")
                {
                    whereConditions.Add($"{columnName} IS NULL");
                }
                else
                {
                    whereConditions.Add($"{columnName} IS NOT NULL");
                }
            }
            else if (key.EndsWith("_gt"))
            {
                string columnName = key.Substring(0, key.Length - 3);
                whereConditions.Add($"{columnName} > {value}");
            }
            else if (key.EndsWith("_lt"))
            {
                string columnName = key.Substring(0, key.Length - 3);
                whereConditions.Add($"{columnName} < {value}");
            }
            else
            {
                whereConditions.Add($"{key} = '{value}'");
            }
        }
        
        if (whereConditions.Count > 0)
        {
            query.Append(" WHERE ");
            query.Append(string.Join(" AND ", whereConditions));
        }
        
        if (!string.IsNullOrEmpty(orderBy))
        {
            query.Append($" ORDER BY {orderBy}");
        }
        
        return query.ToString();
    }

    private static async Task<List<Dictionary<string, object>>> ExecuteQuery(
        string connectionString, string query)
    {
        var results = new List<Dictionary<string, object>>();
        
        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            await connection.OpenAsync();
            
            using (SqlCommand command = new SqlCommand(query, connection))
            {
                command.CommandTimeout = 30;
                
                using (SqlDataReader reader = await command.ExecuteReaderAsync())
                {
                    while (await reader.ReadAsync())
                    {
                        var row = new Dictionary<string, object>();
                        
